def count_snake_numbers(n):
    """Count Snake numbers with exactly n digits"""
    if n == 1:
        return 0  # No 1-digit Snake numbers (need to be >= 10)

    count = 0
    # For each possible first digit (1 to 9)
    for first_digit in range(1, 10):
        # Each of the remaining digits can be 0 to first_digit-1
        # So we have first_digit^(n-1) combinations
        count += first_digit ** (n - 1)

    return count

def count_snake_up_to(num_str):
    """Count Snake numbers <= num_str using digit DP"""
    n = len(num_str)
    if n == 1:
        return 0

    # Memoization for DP
    memo = {}

    def dp(pos, is_limit, is_started, max_allowed_digit, first_digit):
        if pos == n:
            return 1 if is_started else 0

        if (pos, is_limit, is_started, max_allowed_digit, first_digit) in memo:
            return memo[(pos, is_limit, is_started, max_allowed_digit, first_digit)]

        limit = int(num_str[pos]) if is_limit else 9
        result = 0

        # Try placing each valid digit
        for digit in range(0, limit + 1):
            new_is_limit = is_limit and (digit == limit)

            if not is_started:
                # First digit
                if digit > 0:  # Can't start with 0
                    result += dp(pos + 1, new_is_limit, True, digit, digit)
            else:
                # Not first digit
                if digit <= max_allowed_digit:  # Must be <= first digit
                    result += dp(pos + 1, new_is_limit, True, max_allowed_digit, first_digit)

        memo[(pos, is_limit, is_started, max_allowed_digit, first_digit)] = result
        return result

    # Count all Snake numbers with fewer digits
    total = 0
    for digits in range(2, n):
        total += count_snake_numbers(digits)

    # Count Snake numbers with same number of digits
    total += dp(0, True, False, 0, 0)

    return total

def solve(L, R):
    # Count Snake numbers up to R minus Snake numbers up to L-1
    def count_up_to(x):
        return count_snake_up_to(str(x))

    return count_up_to(R) - count_up_to(L - 1)

