    N, X = map(int, input().split())
    foods = []
    for _ in range(N):
        v, a, c = map(int, input().split())
        foods.append((v, a, c))

    # Binary search on the answer
    left, right = 0, 2 * 10**5
    result = 0

    while left <= right:
        mid = (left + right) // 2

        # DP: dp[calories][vitamin1][vitamin2][vitamin3] = True if achievable
        # But we'll use a dictionary to avoid memory issues
        dp = {}
        dp[(0, 0, 0, 0)] = True  # Start with 0 calories and 0 vitamins

        # For each food, update all reachable states
        for v, a, c in foods:
            new_dp = dp.copy()
            for (cal, v1, v2, v3), can_reach in dp.items():
                if not can_reach:
                    continue
                new_cal = cal + c
                new_v1, new_v2, new_v3 = v1, v2, v3
                if v == 1:
                    new_v1 += a
                elif v == 2:
                    new_v2 += a
                else:  # v == 3
                    new_v3 += a

                if new_cal <= X:
                    key = (new_cal, new_v1, new_v2, new_v3)
                    new_dp[key] = True

            dp = new_dp

        # Check if there exists a valid combination with all vitamins >= mid
        found = False
        for (cal, v1, v2, v3), can_reach in dp.items():
            if cal <= X and v1 >= mid and v2 >= mid and v3 >= mid:
                found = True
                break

        if found:
            result = mid
            left = mid + 1
        else:
            right = mid - 1

    print(result)

