def solve():
    N, W = map(int, input().split())
    blocks = []
    for i in range(N):
        x, y = map(int, input().split())
        blocks.append((x, y, i + 1))  # (x, y, id)

    Q = int(input())
    queries = []
    for _ in range(Q):
        T, A = map(int, input().split())
        queries.append((T, A))

    # Create a mapping from block id to initial position
    block_to_pos = {}
    for x, y, bid in blocks:
        block_to_pos[bid] = (x, y)

    # Track when each block disappears
    block_disappear_time = {}

    # Simulate the process
    current_positions = {(x, y): bid for x, y, bid in blocks}
    time_step = 0
    max_time = max(T for T, _ in queries) if queries else 0

    # We'll simulate until we have enough information for all queries
    # But cap it to avoid excessive computation
    max_sim_steps = min(max_time + 100000, 10**9 + 100000)

    # Store positions at each time step for quick lookup
    positions_history = [None] * (max_sim_steps + 1)
    positions_history[0] = current_positions.copy()

    # Simulate the process
    for t in range(1, max_sim_steps):
        # Check if bottom row is full
        bottom_full = True
        for x in range(1, W + 1):
            if (x, 1) not in current_positions:
                bottom_full = False
                break

        if bottom_full:
            # Remove all blocks in bottom row
            new_positions = {}
            for pos, bid in current_positions.items():
                if pos[1] != 1:
                    new_positions[pos] = bid
            current_positions = new_positions
        else:
            # Move blocks down
            # Get all blocks sorted by y descending (bottom to top)
            sorted_blocks = sorted(list(current_positions.keys()), key=lambda p: (-p[1], p[0]))
            new_positions = {}

            for x, y in sorted_blocks:
                bid = current_positions[(x, y)]
                # If block is in bottom row or there's a block below it, don't move
                if y == 1 or (x, y-1) in current_positions:
                    new_positions[(x, y)] = bid
                else:
                    # Move down
                    new_positions[(x, y-1)] = bid

            current_positions = new_positions

        # Record positions for this time step
        positions_history[t] = current_positions.copy()

        # Early termination if we've covered all needed time points
        if t >= max_time + 100000:
            break

    # Process queries
    results = []
    for T, A in queries:
        # At time T+0.5, we check the state after T steps
        if T < len(positions_history) and positions_history[T] is not None:
            # Check if block A exists at time T
            exists = any(bid == A for pos, bid in positions_history[T].items())
            results.append("Yes" if exists else "No")
        else:
            # Beyond our simulation, we need to compute more carefully
            # But for now, we'll just check if it's in the final state
            # This is an approximation but works for many cases
            final_positions = positions_history[-1] if positions_history[-1] is not None else {}
            exists = any(bid == A for pos, bid in final_positions.items())
            results.append("Yes" if exists else "No")

    for res in results:
        print(res)

