def solve():
    N, K = map(int, input().split())
    A = list(map(int, input().split()))
    B = list(map(int, input().split()))
    C = list(map(int, input().split()))

    # Use a min-heap of size K to keep track of the K largest values
    heap = []

    for i in range(N):
        for j in range(N):
            for k in range(N):
                val = A[i] * B[j] + B[j] * C[k] + C[k] * A[i]
                if len(heap) < K:
                    heapq.heappush(heap, val)
                elif val > heap[0]:
                    heapq.heapreplace(heap, val)

    print(heap[0])

