def solve():
    N, K = map(int, input().split())
    A = list(map(int, input().split()))

    # Count how many elements are divisible by each number
    count = defaultdict(int)
    max_val = max(A)

    # For each element, increment count for all its divisors
    for x in A:
        for i in range(1, int(math.sqrt(x)) + 1):
            if x % i == 0:
                count[i] += 1
                if i != x // i:
                    count[x // i] += 1

    # For each element, find maximum possible GCD
    result = []
    for i in range(N):
        max_gcd = 1
        # Check all divisors of A[i]
        a = A[i]
        for j in range(1, int(math.sqrt(a)) + 1):
            if a % j == 0:
                # Check divisor j
                if count[j] >= K:
                    max_gcd = max(max_gcd, j)
                # Check divisor a//j
                if a // j != j and count[a // j] >= K:
                    max_gcd = max(max_gcd, a // j)
        result.append(max_gcd)

    for res in result:
        print(res)

