from collections import deque

def solve():
    N = int(input())
    grid = []
    for _ in range(N):
        grid.append(input().strip())

    # Precompute adjacency list
    adj = [[] for _ in range(N)]
    for i in range(N):
        for j in range(N):
            if grid[i][j] != '-':
                adj[i].append((j, grid[i][j]))

    # Result matrix
    result = [[-1] * N for _ in range(N)]

    # For each starting vertex, run BFS to find shortest palindromic paths
    for start in range(N):
        # BFS queue: (vertex, current_palindrome_string)
        queue = deque([(start, "")])
        visited = set()
        visited.add((start, ""))
        result[start][start] = 0

        while queue:
            node, path_str = queue.popleft()

            # Check all neighbors
            for neighbor, label in adj[node]:
                new_path = path_str + label

                # Check if new_path is palindrome
                if new_path == new_path[::-1]:
                    if result[start][neighbor] == -1:
                        result[start][neighbor] = len(new_path)

                # Continue BFS with this path
                if (neighbor, new_path) not in visited:
                    visited.add((neighbor, new_path))
                    queue.append((neighbor, new_path))

    # Print result
    for i in range(N):
        print(" ".join(map(str, result[i])))

