import math

def solve(N):
    # Try small values of d = x - y
    max_d = min(1000000, int(N**(1/3)) + 1000)

    for d in range(1, max_d):
        # We have x = y + d, so x^3 - y^3 = d*(3*y^2 + 3*d*y + d^2) = N
        # So 3*d*y^2 + 3*d^2*y + d^3 = N
        # 3*d*y^2 + 3*d^2*y + (d^3 - N) = 0

        discriminant = 9 * d**4 - 12 * d * (d**3 - N)
        if discriminant < 0:
            continue

        sqrt_discriminant = int(math.sqrt(discriminant))
        if sqrt_discriminant * sqrt_discriminant != discriminant:
            continue

        numerator1 = -3 * d**2 + sqrt_discriminant
        numerator2 = -3 * d**2 - sqrt_discriminant

        if numerator1 % (6 * d) == 0:
            y = numerator1 // (6 * d)
            if y > 0:
                x = y + d
                if x**3 - y**3 == N:
                    return (x, y)

        if numerator2 % (6 * d) == 0:
            y = numerator2 // (6 * d)
            if y > 0:
                x = y + d
                if x**3 - y**3 == N:
                    return (x, y)

    # Fallback method: try iterating y
    y_max = int(N**(1/3)) + 100000
    for y in range(1, y_max):
        x_cubed = y**3 + N
        x = round(x_cubed**(1/3))

        # Check nearby values since floating point might be imprecise
        for candidate_x in [x-1, x, x+1]:
            if candidate_x > 0 and candidate_x**3 == x_cubed:
                if candidate_x > y:
                    return (candidate_x, y)

    return (-1, -1)

