class Solution:
    def maximumAmount(self, coins: List[List[int]]) -> int:
        m, n = len(coins), len(coins[0])
        dp = {}

        def solve(i, j, neutralizations_left):
            if i == m - 1 and j == n - 1:
                return coins[i][j]

            if i >= m or j >= n:
                return float('-inf')

            if (i, j, neutralizations_left) in dp:
                return dp[(i, j, neutralizations_left)]

            # Go right
            right = solve(i, j + 1, neutralizations_left)
            # Go down
            down = solve(i + 1, j, neutralizations_left)

            best = max(right, down)

            if best == float('-inf'):
                dp[(i, j, neutralizations_left)] = float('-inf')
                return float('-inf')

            current_value = coins[i][j]

            # If we encounter a robber, we can choose to neutralize it
            if current_value < 0 and neutralizations_left > 0:
                # Option 1: Neutralize it (get 0 instead of current_value)
                # Option 2: Don't neutralize it (pay current_value)
                option1 = 0 + best  # Neutralize
                option2 = current_value + best  # Don't neutralize
                result = max(option1, option2)
            else:
                result = current_value + best

            dp[(i, j, neutralizations_left)] = result
            return result

        return solve(0, 0, 2)

class Solution:
    def minMaxWeight(self, n: int, edges: List[List[int]], threshold: int) -> int:
        # Binary search on the answer
        left, right = 1, 10**6
        result = -1

        def canSatisfy(max_weight):
            # Build graph with edges having weight <= max_weight
            graph = [[] for _ in range(n)]
            out_degree = [0] * n

            for u, v, w in edges:
                if w <= max_weight:
                    graph[v].append(u)  # reverse direction for easier reachability check
                    out_degree[u] += 1

            # Check if each node has at most threshold outgoing edges
            for i in range(n):
                if out_degree[i] > threshold:
                    return False

            # Check if node 0 is reachable from all nodes using BFS
            visited = [False] * n
            queue = [0]
            visited[0] = True

            while queue:
                node = queue.pop(0)
                for neighbor in graph[node]:
                    if not visited[neighbor]:
                        visited[neighbor] = True
                        queue.append(neighbor)

            # Check if all nodes are reachable from node 0
            for i in range(n):
                if not visited[i]:
                    return False

            return True

        while left <= right:
            mid = (left + right) // 2
            if canSatisfy(mid):
                result = mid
                right = mid - 1
            else:
                left = mid + 1

        return result

