class Solution:
    def maxDistance(self, s: str, k: int) -> int:
        # Directions mapping
        dirs = {'N': (0, 1), 'S': (0, -1), 'E': (1, 0), 'W': (-1, 0)}

        # Use dynamic programming with states (x, y, changes_used)
        # But we'll track reachable (x, y) positions with minimum changes needed
        # And we'll track the maximum Manhattan distance

        # Instead of tracking all states, we'll use a more efficient approach:
        # At each step, we track all reachable (x, y) positions with their minimum changes used
        # But we also track max distance

        # Start with initial position
        pos_to_min_changes = {(0, 0): 0}
        max_dist = 0

        for char in s:
            new_pos_to_min_changes = {}

            # Process all current positions
            for (x, y), changes_used in pos_to_min_changes.items():
                # Update max distance
                max_dist = max(max_dist, abs(x) + abs(y))

                # Option 1: follow current instruction
                dx, dy = dirs[char]
                new_x, new_y = x + dx, y + dy
                if (new_x, new_y) not in new_pos_to_min_changes:
                    new_pos_to_min_changes[(new_x, new_y)] = changes_used
                else:
                    new_pos_to_min_changes[(new_x, new_y)] = min(new_pos_to_min_changes[(new_x, new_y)], changes_used)

                # Option 2: change instruction (if changes left)
                if changes_used < k:
                    for dir_char, (dx, dy) in dirs.items():
                        if dir_char != char:
                            new_x, new_y = x + dx, y + dy
                            if (new_x, new_y) not in new_pos_to_min_changes:
                                new_pos_to_min_changes[(new_x, new_y)] = changes_used + 1
                            else:
                                new_pos_to_min_changes[(new_x, new_y)] = min(new_pos_to_min_changes[(new_x, new_y)], changes_used + 1)

            pos_to_min_changes = new_pos_to_min_changes

        # Final check for remaining positions
        for (x, y), _ in pos_to_min_changes.items():
            max_dist = max(max_dist, abs(x) + abs(y))

        return max_dist

class Solution:
    def minimumIncrements(self, nums: List[int], target: List[int]) -> int:
        total_operations = 0

        for t in target:
            # Check if any existing number in nums is divisible by t
            found = False
            min_cost = float('inf')

            for num in nums:
                if num % t == 0:
                    found = True
                    break
                else:
                    # Calculate cost to make num divisible by t
                    remainder = num % t
                    cost = t - remainder
                    min_cost = min(min_cost, cost)

            # If no existing number is divisible by t, we need to pay the minimum cost
            if not found:
                total_operations += min_cost

        return total_operations

