class Solution:
    def maxSubstringLength(self, s: str, k: int) -> bool:
        if k == 0:
            return True

        n = len(s)

        # Compute first and last occurrence of each character
        first = {}
        last = {}
        for i, c in enumerate(s):
            if c not in first:
                first[c] = i
            last[c] = i

        # Find all maximal special substrings
        special_ranges = []
        i = 0
        while i < n:
            # Extend window from position i
            j = i
            valid_chars = set()

            while j < n:
                c = s[j]
                valid_chars.add(c)

                # Check if all characters in current window are valid (first and last within window)
                valid = True
                for char in valid_chars:
                    if first[char] < i or last[char] > j:
                        valid = False
                        break

                if not valid:
                    # Backtrack: remove last character and stop extending
                    valid_chars.remove(c)
                    j -= 1
                    break

                j += 1

            # If we found a valid special substring
            if j > i:
                special_ranges.append((i, j))
                i = j + 1
            else:
                i += 1

        # Remove the entire string if it's special (not allowed)
        final_ranges = []
        for start, end in special_ranges:
            if start == 0 and end == n - 1:
                continue
            final_ranges.append((start, end))

        # Greedily select at most k disjoint substrings
        if not final_ranges:
            return k == 0

        # Sort by end time
        final_ranges.sort(key=lambda x: x[1])

        selected = 0
        last_end = -1

        for start, end in final_ranges:
            if start > last_end:  # No overlap
                selected += 1
                last_end = end
                if selected >= k:
                    return True

        return selected >= k

