class Solution:
    def maxDistance(self, side: int, points: List[List[int]], k: int) -> int:
        def manhattan_dist(p1, p2):
            return abs(p1[0] - p2[0]) + abs(p1[1] - p2[1])

        def can_select(min_dist):
            # Greedily select points such that all selected points have at least min_dist distance
            # Sort by x-coordinate first
            points_sorted = sorted(points, key=lambda x: x[0])

            selected = []
            for point in points_sorted:
                # Check if this point can be added to selected set
                valid = True
                for selected_point in selected:
                    if manhattan_dist(point, selected_point) < min_dist:
                        valid = False
                        break

                if valid:
                    selected.append(point)
                    if len(selected) == k:
                        return True

            return len(selected) >= k

        # Binary search on the answer
        left = 0
        right = 2 * side  # Maximum possible Manhattan distance
        result = 0

        while left <= right:
            mid = (left + right) // 2
            if can_select(mid):
                result = mid
                left = mid + 1
            else:
