class Solution:
    def longestPalindromicSubsequence(self, s: str, k: int) -> int:
        def cost(a, b):
            if a == b:
                return 0
            pos_a = ord(a) - ord('a')
            pos_b = ord(b) - ord('a')
            direct = abs(pos_a - pos_b)
            circular = 26 - direct
            return min(direct, circular)

        from functools import lru_cache

        @lru_cache(None)
        def dp(i, j, ops):
            if i > j:
                return 0
            if i == j:
                return 1

            if s[i] == s[j]:
                return 2 + dp(i + 1, j - 1, ops)
            else:
                # Option 1: change s[i] to match s[j]
                cost_i = cost(s[i], s[j])
                res1 = 0
                if cost_i <= ops:
                    res1 = 2 + dp(i + 1, j - 1, ops - cost_i)

                # Option 2: change s[j] to match s[i]
                cost_j = cost(s[j], s[i])
                res2 = 0
                if cost_j <= ops:
                    res2 = 2 + dp(i + 1, j - 1, ops - cost_j)

                # Option 3: skip either i or j
                res3 = dp(i + 1, j, ops)
                res4 = dp(i, j - 1, ops)

                return max(res1, res2, res3, res4)

        return dp(0, len(s) - 1, k)

class Solution:
    def maxSum(self, nums: List[int], k: int, m: int) -> int:
        n = len(nums)

        # Generate all valid subarrays with length >= m
        valid_subarrays = []
        for i in range(n):
            current_sum = 0
            for j in range(i, n):
