            for j in range(k + 1):
                dp[i][j] = max(dp[i][j], dp[i-1][j])

            # Take current subarray
            # Find the latest previous subarray that doesn't overlap
            for j in range(1, min(i, k) + 1):
                # Search backwards for non-overlapping subarray
                for prev_idx in range(i-1, 0, -1):
                    prev_start, prev_end, _ = valid_subarrays[prev_idx-1]
                    if prev_end < start:  # No overlap
                        dp[i][j] = max(dp[i][j], dp[prev_idx][j-1] + sub_sum)
                        break
                else:
                    # If no previous subarray exists or all overlap, we can start with this
                    if j == 1:
                        dp[i][j] = max(dp[i][j], sub_sum)

        return dp[len(valid_subarrays)][k]

class Solution:
    def generateString(self, str1: str, str2: str) -> str:
        n, m = len(str1), len(str2)
        if m == 0:
            return ""
        if n == 0:
            return ""

        total_len = n + m - 1
        result = [''] * total_len

        # First pass: place str2 where needed (T positions)
        for i in range(n):
            if str1[i] == 'T':
                # Place str2 starting at position i
                for j in range(m):
                    if i + j >= total_len:
                        return ""
                    if result[i + j] and result[i + j] != str2[j]:
                        return ""
                    result[i + j] = str2[j]

        # Second pass: verify F constraints and fill gaps with minimal chars
        for i in range(n):
            if str1[i] == 'F':
                # word[i:i+m] should NOT equal str2
                substring = []
                for j in range(m):
                    if i + j >= total_len:
                        return ""
                    if result[i + j] == '':
                        substring.append('?')
                    else:
                        substring.append(result[i + j])

                # If we have complete substring, check if it equals str2
                if len(substring) == m and all(c != '?' for c in substring):
                    if ''.join(substring) == str2:
                        return ""

        # Fill remaining empty positions with 'a' to keep lexicographically small
        for i in range(total_len):
            if result[i] == '':
                result[i] = 'a'

        # Final verification - check all constraints
        for i in range(n):
            if str1[i] == 'T':
                # Check if word[i:i+m] == str2
                substring = ''.join(result[i:i+m])
                if substring != str2:
                    return ""
            elif str1[i] == 'F':
                # Check if word[i:i+m] != str2
                substring = ''.join(result[i:i+m])
                if substring == str2:
                    return ""

        return ''.join(result)

class Solution:
    def numOfUnplacedFruits(self, fruits: List[int], baskets: List[int]) -> int:
        # Keep track of which baskets are used and what fruit type they hold
        basket_used = {}
        unplaced_count = 0

        for fruit in fruits:
            placed = False
            # Find the leftmost available basket that can hold this fruit
            for i in range(len(baskets)):
                if i not in basket_used and baskets[i] >= fruit:
                    basket_used[i] = fruit
                    placed = True
                    break

            if not placed:
                unplaced_count += 1

        return unplaced_count

class Solution:
    def maxSubarrays(self, n: int, conflictingPairs: List[List[int]]) -> int:
        def countValidSubarrays(pairs):
            # Count subarrays that don't contain both elements of any pair
            count = 0

            # For each subarray [l,r], check if it's valid
            for l in range(n):
                for r in range(l, n):
                    valid = True
                    # Check all pairs
                    for a, b in pairs:
                        # Check if both a and b are in subarray [l,r]
                        # Convert 1-indexed to 0-indexed
                        if (a-1 >= l and a-1 <= r) and (b-1 >= l and b-1 <= r):
                            valid = False
                            break
                    if valid:
                        count += 1

            return count

        # Try removing each pair and take maximum
        max_count = 0
        for i in range(len(conflictingPairs)):
            # Create new pairs list without pair i
            new_pairs = conflictingPairs[:i] + conflictingPairs[i+1:]
            count = countValidSubarrays(new_pairs)
            max_count = max(max_count, count)

        return max_count

class Solution:
    def solveQueries(self, nums: List[int], queries: List[int]) -> List[int]:
        # Preprocess: for each value, store all indices where it appears
        value_to_indices = {}
        for i, num in enumerate(nums):
            if num not in value_to_indices:
                value_to_indices[num] = []
            value_to_indices[num].append(i)

        result = []

        for query_idx in queries:
            target_value = nums[query_idx]
            indices_with_same_value = value_to_indices.get(target_value, [])

            # If there's only one occurrence, return -1
            if len(indices_with_same_value) <= 1:
                result.append(-1)
                continue

            min_distance = float('inf')

            # Check all indices with the same value
            for idx in indices_with_same_value:
                if idx == query_idx:
                    continue

                # Calculate circular distance
                direct_distance = abs(idx - query_idx)
                circular_distance = len(nums) - direct_distance
                distance = min(direct_distance, circular_distance)

                min_distance = min(min_distance, distance)

            result.append(min_distance)

        return result

class Solution:
    def minZeroArray(self, nums: List[int], queries: List[List[int]]) -> int:
        def canMakeZero(k):
            # Create a difference array to track operations
            diff = [0] * (len(nums) + 1)

            # Apply first k queries
            for i in range(k):
                l, r, val = queries[i]
                diff[l] += val
                diff[r + 1] -= val

            # Compute actual decrements for each position
            current = [0] * len(nums)
            current[0] = diff[0]
            for i in range(1, len(nums)):
                current[i] = current[i-1] + diff[i]

            # Check if we can make all elements 0
            # We need to ensure that for each position, 
            # the initial value minus the total decrements >= 0
            for i in range(len(nums)):
                if nums[i] - current[i] < 0:
                    return False
            return True

        # Binary search on the answer
        left, right = 0, len(queries)
        result = -1

        while left <= right:
            mid = (left + right) // 2
            if canMakeZero(mid):
                result = mid
                right = mid - 1
            else:
                left = mid + 1

        return result

class Solution:
    def beautifulNumbers(self, l: int, r: int) -> int:
        def is_beautiful(num):
            if num == 0:
                return False

            digit_sum = 0
            digit_product = 1

            while num > 0:
                digit = num % 10
                digit_sum += digit
                digit_product *= digit
                num //= 10

            return digit_product % digit_sum == 0 if digit_sum != 0 else False

        def count_beautiful(limit):
            # Convert limit to string for digit manipulation
            s = str(limit)
            n = len(s)

            # Memoization cache
            memo = {}

            def dfs(pos, tight, started, digit_sum, digit_product):
                # Base case: we've processed all digits
                if pos == n:
                    if started and digit_sum != 0 and digit_product % digit_sum == 0:
                        return 1
                    return 0

                # Check memoization
                state = (pos, tight, started, digit_sum, digit_product)
                if state in memo:
                    return memo[state]

                # Determine the upper limit for current digit
                limit = int(s[pos]) if tight else 9
                result = 0

                # Try all possible digits at current position
                for digit in range(0, limit + 1):
                    new_tight = tight and (digit == limit)
                    new_started = started or (digit != 0)

                    # Update sum and product
                    new_sum = digit_sum + (digit if new_started else 0)
                    new_product = digit_product * (digit if new_started else 1)

                    # If we're not starting with 0, we can proceed
                    if not started and digit == 0:
                        # Continue without starting
                        result += dfs(pos + 1, new_tight, False, 0, 1)
                    else:
                        # Continue with current digit
                        result += dfs(pos + 1, new_tight, True, new_sum, new_product)

                memo[state] = result
                return result

            return dfs(0, True, False, 0, 1)

        # Count beautiful numbers up to r and subtract those up to l-1
        return count_beautiful(r) - count_beautiful(l - 1)

class Solution:
    def maxContainers(self, n: int, w: int, maxWeight: int) -> int:
        total_cells = n * n
        max_containers_by_weight = maxWeight // w
        return min(total_cells, max_containers_by_weight)

class Solution:
    def numberOfComponents(self, properties: List[List[int]], k: int) -> int:
        def intersect(a, b):
            set_a = set(a)
            set_b = set(b)
            return len(set_a & set_b)

        n = len(properties)
        if n == 0:
            return 0

        # Build adjacency list
        adj = [[] for _ in range(n)]

        for i in range(n):
            for j in range(i + 1, n):
                if intersect(properties[i], properties[j]) >= k:
                    adj[i].append(j)
                    adj[j].append(i)

        # Count connected components using DFS
        visited = [False] * n
        components = 0

        for i in range(n):
            if not visited[i]:
                # DFS to mark all nodes in this component
                stack = [i]
                visited[i] = True

                while stack:
                    node = stack.pop()
                    for neighbor in adj[node]:
                        if not visited[neighbor]:
                            visited[neighbor] = True
                            stack.append(neighbor)

                components += 1

        return components

class Solution:
    def minCosts(self, cost: List[int]) -> List[int]:
        n = len(cost)
        answer = [0] * n
        answer[0] = cost[0]
        for i in range(1, n):
            answer[i] = min(cost[i], answer[i-1])
        return answer

class Solution:
    def longestPalindrome(self, s: str, t: str) -> int:
        def is_palindrome(string):
            return string == string[::-1]

        max_len = 0

        # Check if there's a palindrome in s alone
        for i in range(len(s)):
            for j in range(i + 1, len(s) + 1):
                if is_palindrome(s[i:j]):
                    max_len = max(max_len, j - i)

        # Check if there's a palindrome in t alone
        for i in range(len(t)):
            for j in range(i + 1, len(t) + 1):
                if is_palindrome(t[i:j]):
                    max_len = max(max_len, j - i)

        # Check combinations: prefix of s + suffix of t
        for i in range(len(s) + 1):
            for j in range(len(t) + 1):
                combined = s[:i] + t[j:]
                if is_palindrome(combined):
                    max_len = max(max_len, len(combined))

        # Check combinations: prefix of t + suffix of s  
        for i in range(len(t) + 1):
            for j in range(len(s) + 1):
                combined = t[:i] + s[j:]
                if is_palindrome(combined):
                    max_len = max(max_len, len(combined))

        return max_len

class Solution:
    def minimumPairRemoval(self, nums: List[int]) -> int:
        operations = 0

        while True:
            # Check if array is already non-decreasing
            is_sorted = True
            for i in range(1, len(nums)):
                if nums[i] < nums[i-1]:
                    is_sorted = False
                    break

            if is_sorted:
                break

            # Find the leftmost adjacent pair with minimum sum
            min_sum = float('inf')
            min_index = -1

            for i in range(len(nums) - 1):
                current_sum = nums[i] + nums[i+1]
                if current_sum < min_sum:
                    min_sum = current_sum
                    min_index = i

            # Replace the pair with their sum
            new_nums = []
            i = 0
            while i < len(nums):
                if i == min_index:
                    new_nums.append(nums[i] + nums[i+1])
                    i += 2
                else:
                    new_nums.append(nums[i])
                    i += 1

            nums = new_nums
            operations += 1

        return operations

class Solution:
    def maxAdjacentDistance(self, nums: list[int]) -> int:
        if len(nums) < 2:
            return 0

        max_diff = 0

        # Check all adjacent pairs in the circular array
        for i in range(len(nums)):
            next_index = (i + 1) % len(nums)
            diff = abs(nums[i] - nums[next_index])
            max_diff = max(max_diff, diff)

        return max_diff

class Solution:
    def longestSpecialPath(self, edges: List[List[int]], nums: List[int]) -> List[int]:
        # Build adjacency list representation of the tree
        graph = [[] for _ in range(len(nums))]
        for u, v, length in edges:
            graph[u].append((v, length))
            graph[v].append((u, length))

        max_length = 0
        min_nodes = float('inf')

        def dfs(node, parent, path_values, current_length, node_count):
            nonlocal max_length, min_nodes

            # Update global max length and count
            if current_length > max_length:
                max_length = current_length
                min_nodes = node_count
            elif current_length == max_length:
                min_nodes = min(min_nodes, node_count)

            # Try all children
            for neighbor, length in graph[node]:
                if neighbor != parent:  # Don't go back to parent
                    # Check if we can extend the path
                    if nums[neighbor] not in path_values:
                        # Add neighbor to path
                        new_path_values = path_values | {nums[neighbor]}
                        dfs(neighbor, node, new_path_values, current_length + length, node_count + 1)

        # Start DFS from root (node 0)
        dfs(0, -1, {nums[0]}, 0, 1)

        # If no special path found (only single nodes), return [0, 1]
        if max_length == 0 and min_nodes == float('inf'):
            return [0, 1]

        return [max_length, min_nodes]

class Solution:
    def findValidPair(self, s: str) -> str:
        # Count frequency of each digit
        freq = {}
        for char in s:
            freq[char] = freq.get(char, 0) + 1

        # Check each adjacent pair
        for i in range(len(s) - 1):
            first_digit = s[i]
            second_digit = s[i + 1]

            # Check if digits are different
            if first_digit != second_digit:
                # Check if each digit appears exactly as many times as its value
                if freq[first_digit] == int(first_digit) and freq[second_digit] == int(second_digit):
                    return first_digit + second_digit

        return ""

class Solution:
    def minCostGoodCaption(self, caption: str) -> str:
        n = len(caption)
        if n == 0:
            return ""

        INF = float('inf')

        # dp[i][ch][count] = min operations to reach position i with last char ch and count consecutive chars
        # We'll use a more efficient approach with just tracking (i, ch, count) states
        dp = {}
        parent = {}

        # Base case: before processing any character
        dp[(-1, '', 0)] = 0

        for i in range(n):
            for (prev_char, count), cost in list(dp.items()):
                if prev_char == '':
                    # Starting state
                    for ch in 'abcdefghijklmnopqrstuvwxyz':
                        new_cost = cost + (1 if ch != caption[i] else 0)
                        dp[(i, ch, 1)] = min(dp.get((i, ch, 1), INF), new_cost)
                        if dp[(i, ch, 1)] == new_cost:
                            parent[(i, ch, 1)] = (prev_char, count)
                else:
                    # Extend existing group or start new one
                    for ch in 'abcdefghijklmnopqrstuvwxyz':
                        new_cost = cost + (1 if ch != caption[i] else 0)
                        new_count = count + 1 if ch == prev_char else 1

                        # Skip invalid states (ending with less than 3 chars)
                        if i == n - 1 and new_count < 3:
                            continue

                        dp[(i, ch, new_count)] = min(dp.get((i, ch, new_count), INF), new_cost)
                        if dp[(i, ch, new_count)] == new_cost:
                            parent[(i, ch, new_count)] = (prev_char, count)

        # Find best final state
        min_cost = INF
        final_state = None

        for ch in 'abcdefghijklmnopqrstuvwxyz':
            for count in range(3, n + 1):  # reasonable upper bound
                if (n-1, ch, count) in dp:
                    if dp[(n-1, ch, count)] < min_cost:
                        min_cost = dp[(n-1, ch, count)]
                        final_state = (n-1, ch, count)

        if min_cost == INF:
            return ""

        # Reconstruct path
        path = []
        current = final_state
        while current in parent:
            pos, ch, count = current
            path.append(ch)
            current = parent[current]

        path.reverse()
        return ''.join(path)

class Solution:
    def sumOfGoodNumbers(self, nums: list[int], k: int) -> int:
        total_sum = 0
        n = len(nums)

        for i in range(n):
            is_good = True

            # Check left neighbor at index i - k
            if i - k >= 0:
                if nums[i] <= nums[i - k]:
                    is_good = False

            # Check right neighbor at index i + k
            if i + k < n:
                if nums[i] <= nums[i + k]:
                    is_good = False

            if is_good:
                total_sum += nums[i]

        return total_sum

class Solution:
    def transformArray(self, nums: List[int]) -> List[int]:
        # Replace each even number with 0 and each odd number with 1
        for i in range(len(nums)):
            if nums[i] % 2 == 0:
                nums[i] = 0
            else:
                nums[i] = 1

        # Sort the modified array in non-decreasing order
        nums.sort()

        return nums

class Solution:
    def minCost(self, nums: List[int]) -> int:
        # If length is less than 3, just return the max element
        if len(nums) < 3:
            return max(nums)

        # For longer arrays, we'll use a greedy approach
        # Always take the two smallest elements from the first 3 elements
        cost = 0
        i = 0

        while i < len(nums):
            if len(nums) - i >= 3:
                # Take the two smallest from first 3 elements
                first_three = sorted(nums[i:i+3])
                cost += first_three[1]  # max of the two smallest
                i += 3
            else:
                # Less than 3 elements left, remove all together
                cost += max(nums[i:])
                break

        return cost

class Solution:
    def totalNumbers(self, digits: List[int]) -> int:
        from collections import Counter

        # Count frequency of each digit
        count = Counter(digits)

        # Generate all possible 3-digit combinations
        valid_numbers = set()

        # Try all combinations of 3 digits
        for i in range(10):
            for j in range(10):
                for k in range(10):
                    # Create a temporary counter for this combination
                    temp_count = Counter([i, j, k])

                    # Check if this combination is valid
                    valid = True
                    for digit, freq in temp_count.items():
                        if count[digit] < freq:
                            valid = False
                            break

                    # If valid and forms a valid 3-digit even number
                    if valid and i != 0 and k % 2 == 0:
                        valid_numbers.add((i, j, k))

        return len(valid_numbers)

class Solution:
    def longestCommonPrefix(self, words: List[str], k: int) -> List[int]:
        def get_common_prefix_length(s1, s2):
            # Returns length of common prefix between s1 and s2
            min_len = min(len(s1), len(s2))
            for i in range(min_len):
                if s1[i] != s2[i]:
                    return i
            return min_len

        result = []
        n = len(words)

        for i in range(n):
            # Remove words[i]
            remaining_words = words[:i] + words[i+1:]

            if len(remaining_words) < k:
                result.append(0)
            else:
                # Sort remaining words to make prefix computation easier
                sorted_words = sorted(remaining_words)

                # Find the maximum common prefix among any k words
                max_prefix = 0

                # Check all combinations of k consecutive words in sorted list
                for start in range(len(sorted_words) - k + 1):
                    # Get first k words starting from 'start'
                    prefix_len = len(sorted_words[start])
                    for j in range(1, k):
                        prefix_len = min(prefix_len, get_common_prefix_length(sorted_words[start], sorted_words[start + j]))
                    max_prefix = max(max_prefix, prefix_len)

                result.append(max_prefix)

        return result
